class Solution:
    def verticalTraversal(self, root):
        nodes = []
        def dfs(node, r, c):
            if not node:
                return
            nodes.append((c, r, node.val))
            dfs(node.left, r + 1, c - 1)
            dfs(node.right, r + 1, c + 1)
        dfs(root, 0, 0)
        nodes.sort()
        res = []
        cur_col = None
        for c, r, v in nodes:
            if c != cur_col:
                res.append([])
                cur_col = c
            res[-1].append(v)
        return res

