var verticalTraversal = function(root) {
    const cols = new Map();
    const stack = [[root, 0, 0]];
    while (stack.length) {
        const [node, r, c] = stack.pop();
        if (node === null) continue;
        if (!cols.has(c)) cols.set(c, []);
        cols.get(c).push([r, node.val]);
        stack.push([node.left, r + 1, c - 1]);
        stack.push([node.right, r + 1, c + 1]);
    }
    const keys = [...cols.keys()].sort((a, b) => a - b);
    const res = [];
    for (const c of keys) {
        const entries = cols.get(c).slice().sort((a, b) => a[0] - b[0] || a[1] - b[1]);
        res.push(entries.map(e => e[1]));
    }
    return res;
};
